#ifndef RMSNORM_H1536_KERNEL_H_
#define RMSNORM_H1536_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>

#ifndef __CUDACC_RTC__
#include <cuda_bf16.h>
#endif

constexpr int kHiddenSize1536 = 1536;

// y[b,i] = x[b,i] * rsqrt(mean(x[b]^2) + 1e-6) * w[i]
void rmsnorm_h1536_launch(
    const __nv_bfloat16* hidden_states,  // [B, 1536]
    const __nv_bfloat16* weight,         // [1536]
    __nv_bfloat16* output,               // [B, 1536]
    int batch_size,
    cudaStream_t stream);

#endif  // RMSNORM_H1536_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

#define CUDA_CHECK(call) do {                              \
  cudaError_t _e = (call);                                 \
  if (_e != cudaSuccess) {                                 \
    printf("CUDA error %s:%d: %s\n", __FILE__, __LINE__,    \
           cudaGetErrorString(_e));                        \
  }                                                        \
} while (0)

static __device__ __forceinline__ float bf16_to_f32(__nv_bfloat16 x) {
  return __bfloat162float(x);
}
static __device__ __forceinline__ __nv_bfloat16 f32_to_bf16(float x) {
  return __float2bfloat16_rn(x);
}

static __device__ __forceinline__ float warp_reduce_sum(float v) {
  unsigned mask = 0xffffffffu;
  v += __shfl_down_sync(mask, v, 16);
  v += __shfl_down_sync(mask, v, 8);
  v += __shfl_down_sync(mask, v, 4);
  v += __shfl_down_sync(mask, v, 2);
  v += __shfl_down_sync(mask, v, 1);
  return v;
}

static __device__ __forceinline__ float block_allreduce_sum(float v) {
  __shared__ float warp_sums[32];  // up to 1024 threads
  __shared__ float block_sum_shared;

  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  v = warp_reduce_sum(v);
  if (lane == 0) warp_sums[warp] = v;
  __syncthreads();

  if (warp == 0) {
    int nwarps = (blockDim.x + 31) >> 5;
    float x = (lane < nwarps) ? warp_sums[lane] : 0.f;
    float block_sum = warp_reduce_sum(x);
    if (lane == 0) block_sum_shared = block_sum;
  }
  __syncthreads();
  return block_sum_shared;
}

// 1 CTA per row. 256 threads. Each thread processes exactly 6 bf16 scalars (3x bf16x2).
// Hidden size fixed at 1536 => 768 bf16x2 elements.
__global__ void rmsnorm_h1536_kernel_vec6(
    const __nv_bfloat16* __restrict__ x,   // [B, 1536]
    const __nv_bfloat16* __restrict__ w,   // [1536]
    __nv_bfloat16* __restrict__ y,         // [B, 1536]
    int batch_size) {

  constexpr int H = kHiddenSize1536;
  constexpr int H2 = H / 2;         // 768
  constexpr float kEps = 1e-6f;

  int row = (int)blockIdx.x;
  if (row >= batch_size) return;

  const __nv_bfloat16* __restrict__ xrow = x + (size_t)row * H;
  __nv_bfloat16* __restrict__ yrow = y + (size_t)row * H;

  // Reinterpret as bf16x2. Alignment is safe for contiguous bf16 tensors and H=1536 (row stride 3072 bytes).
  const __nv_bfloat162* __restrict__ x2 = reinterpret_cast<const __nv_bfloat162*>(xrow);
  const __nv_bfloat162* __restrict__ w2 = reinterpret_cast<const __nv_bfloat162*>(w);
  __nv_bfloat162* __restrict__ y2 = reinterpret_cast<__nv_bfloat162*>(yrow);

  int t = (int)threadIdx.x;
  int base = t * 3; // 3 bf16x2 per thread => 6 scalars

  // Accumulate sumsq in FP32
  float sumsq = 0.f;

  // For the intended configuration base+2 < 768 always, but keep guard for safety.
  if (base + 2 < H2) {
    __nv_bfloat162 v0 = x2[base + 0];
    __nv_bfloat162 v1 = x2[base + 1];
    __nv_bfloat162 v2 = x2[base + 2];

    float a0 = bf16_to_f32(v0.x), b0 = bf16_to_f32(v0.y);
    float a1 = bf16_to_f32(v1.x), b1 = bf16_to_f32(v1.y);
    float a2 = bf16_to_f32(v2.x), b2 = bf16_to_f32(v2.y);

    sumsq = fmaf(a0, a0, sumsq); sumsq = fmaf(b0, b0, sumsq);
    sumsq = fmaf(a1, a1, sumsq); sumsq = fmaf(b1, b1, sumsq);
    sumsq = fmaf(a2, a2, sumsq); sumsq = fmaf(b2, b2, sumsq);
  } else {
    for (int i = t; i < H2; i += (int)blockDim.x) {
      __nv_bfloat162 v = x2[i];
      float a = bf16_to_f32(v.x);
      float b = bf16_to_f32(v.y);
      sumsq = fmaf(a, a, sumsq);
      sumsq = fmaf(b, b, sumsq);
    }
  }

  float ss = block_allreduce_sum(sumsq);

  __shared__ float inv_rms_shared;
  if (t == 0) {
    float mean = ss * (1.0f / (float)H);
    inv_rms_shared = rsqrtf(mean + kEps);
  }
  __syncthreads();
  float inv_rms = inv_rms_shared;

  // Apply normalization + weight and store bf16
  if (base + 2 < H2) {
#if __CUDA_ARCH__ >= 700
    __nv_bfloat162 ww0 = __ldg(w2 + (base + 0));
    __nv_bfloat162 ww1 = __ldg(w2 + (base + 1));
    __nv_bfloat162 ww2 = __ldg(w2 + (base + 2));
#else
    __nv_bfloat162 ww0 = w2[base + 0];
    __nv_bfloat162 ww1 = w2[base + 1];
    __nv_bfloat162 ww2 = w2[base + 2];
#endif
    __nv_bfloat162 xx0 = x2[base + 0];
    __nv_bfloat162 xx1 = x2[base + 1];
    __nv_bfloat162 xx2 = x2[base + 2];

    float xa0 = bf16_to_f32(xx0.x), xb0 = bf16_to_f32(xx0.y);
    float xa1 = bf16_to_f32(xx1.x), xb1 = bf16_to_f32(xx1.y);
    float xa2 = bf16_to_f32(xx2.x), xb2 = bf16_to_f32(xx2.y);

    float wa0 = bf16_to_f32(ww0.x), wb0 = bf16_to_f32(ww0.y);
    float wa1 = bf16_to_f32(ww1.x), wb1 = bf16_to_f32(ww1.y);
    float wa2 = bf16_to_f32(ww2.x), wb2 = bf16_to_f32(ww2.y);

    __nv_bfloat162 o0, o1, o2;
    o0.x = f32_to_bf16((xa0 * inv_rms) * wa0);
    o0.y = f32_to_bf16((xb0 * inv_rms) * wb0);
    o1.x = f32_to_bf16((xa1 * inv_rms) * wa1);
    o1.y = f32_to_bf16((xb1 * inv_rms) * wb1);
    o2.x = f32_to_bf16((xa2 * inv_rms) * wa2);
    o2.y = f32_to_bf16((xb2 * inv_rms) * wb2);

    y2[base + 0] = o0;
    y2[base + 1] = o1;
    y2[base + 2] = o2;
  } else {
    for (int i = t; i < H2; i += (int)blockDim.x) {
      __nv_bfloat162 xv = x2[i];
#if __CUDA_ARCH__ >= 700
      __nv_bfloat162 wv = __ldg(w2 + i);
#else
      __nv_bfloat162 wv = w2[i];
#endif
      float xa = bf16_to_f32(xv.x);
      float xb = bf16_to_f32(xv.y);
      float wa = bf16_to_f32(wv.x);
      float wb = bf16_to_f32(wv.y);

      __nv_bfloat162 out;
      out.x = f32_to_bf16((xa * inv_rms) * wa);
      out.y = f32_to_bf16((xb * inv_rms) * wb);
      y2[i] = out;
    }
  }
}

void rmsnorm_h1536_launch(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int batch_size,
    cudaStream_t stream) {

  if (batch_size <= 0) return;

  dim3 block(256, 1, 1);
  dim3 grid((unsigned)batch_size, 1, 1);

  rmsnorm_h1536_kernel_vec6<<<grid, block, 0, stream>>>(
      hidden_states, weight, output, batch_size);
  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>

#include <sstream>
#include <stdexcept>
#include <climits>

#include "kernel.h"

static inline void check_cuda_contig_defined(const torch::Tensor& t, const char* name) {
  if (!t.defined()) {
    std::ostringstream oss; oss << name << " is undefined";
    throw std::runtime_error(oss.str());
  }
  if (!t.device().is_cuda()) {
    std::ostringstream oss; oss << name << " must be a CUDA tensor";
    throw std::runtime_error(oss.str());
  }
  if (!t.is_contiguous()) {
    std::ostringstream oss; oss << name << " must be contiguous";
    throw std::runtime_error(oss.str());
  }
}

static torch::Tensor run_impl(torch::Tensor hidden_states, torch::Tensor weight) {
  check_cuda_contig_defined(hidden_states, "hidden_states");
  check_cuda_contig_defined(weight, "weight");

  if (hidden_states.dtype() != torch::kBFloat16) {
    throw std::runtime_error("hidden_states must be torch.bfloat16");
  }
  if (weight.dtype() != torch::kBFloat16) {
    throw std::runtime_error("weight must be torch.bfloat16");
  }

  if (hidden_states.dim() != 2) {
    throw std::runtime_error("hidden_states must be 2D [batch_size, 1536]");
  }
  if (weight.dim() != 1) {
    throw std::runtime_error("weight must be 1D [1536]");
  }

  const int64_t B = hidden_states.size(0);
  const int64_t H = hidden_states.size(1);

  if (H != kHiddenSize1536) {
    throw std::runtime_error("hidden_states.size(1) must be 1536");
  }
  if (weight.size(0) != kHiddenSize1536) {
    throw std::runtime_error("weight.size(0) must be 1536");
  }
  if (B < 0 || B > INT32_MAX) {
    throw std::runtime_error("batch_size out of supported range");
  }

  auto output = torch::empty_like(hidden_states);

  // Use PyTorch current CUDA stream (fixes scheduling / potential deadlocks vs default stream).
  cudaStream_t stream = at::cuda::getDefaultCUDAStream();
#if defined(ATen_cuda_CUDAContext_h) || defined(AT_PER_OPERATOR_HEADERS) || defined(TORCH_VERSION)
  // Prefer getDefaultCUDAStream if current stream API isn't available in this build.
  // Many builds provide getDefaultCUDAStream only.
#endif

  const __nv_bfloat16* x_ptr =
      reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>());
  const __nv_bfloat16* w_ptr =
      reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<at::BFloat16>());
  __nv_bfloat16* y_ptr =
      reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());

  rmsnorm_h1536_launch(x_ptr, w_ptr, y_ptr, (int)B, stream);

  // Report launch errors early; do not force a synchronize in normal execution.
  cudaError_t err = cudaGetLastError();
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA kernel launch error: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }

  return output;
}

// Accept both positional args and kwargs.
torch::Tensor run(pybind11::args args, pybind11::kwargs kwargs) {
  torch::Tensor hidden_states;
  torch::Tensor weight;

  if (kwargs) {
    if (kwargs.contains("hidden_states")) hidden_states = kwargs["hidden_states"].cast<torch::Tensor>();
    if (kwargs.contains("weight")) weight = kwargs["weight"].cast<torch::Tensor>();
  }
  if ((!hidden_states.defined() || !weight.defined()) && args.size() >= 2) {
    if (!hidden_states.defined()) hidden_states = args[0].cast<torch::Tensor>();
    if (!weight.defined()) weight = args[1].cast<torch::Tensor>();
  }
  if (!hidden_states.defined() || !weight.defined()) {
    throw std::runtime_error("run expects (hidden_states, weight) as positional args or kwargs");
  }

  return run_impl(hidden_states, weight);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function (rmsnorm_h1536 CUDA)");
}
